scwin.ondataload = function () {
  // <%= GauceUtil.getCodeList("FM018",2,"10") %>,<%= GauceUtil.getCodeList("FM018",2,"20") %>,<%= GauceUtil.getCodeList("FM018",2,"30") %>">
  let dltStr = "dlt_commonCodeFI003"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
  let dlt = $c.gus.object($p, dltStr); // 데이터 리스트 객체
  $c.data.dataListFilter($p, dlt, "fltrCd2 == '1'"); //$c.data.dataListFilter 함수를 이용해서 필터

  dltStr = "dlt_commonCodeFM018"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
  dlt = $c.gus.object($p, dltStr); // 데이터 리스트 객체
  $c.data.dataListFilter($p, dlt, "fltrCd1 == '10' || fltrCd1 == '20' || fltrCd1 == '30'"); //$c.data.dataListFilter 함수를 이용해서 필터

  //원으로 세팅
  lc_payCrcCd.setValue(scwin.KOREA_WON);
  $c.gus.cfTurnCreateFlag($p, false);
  lc_evidClsCd.focus();
  $c.gus.cfDisableObjects($p, [ed_payAmtFcrc]);
  //ed_payAmtFcrc.Text = 0; 
  ed_clntNo1.hide();
  lc_acqCls.setSelectedIndex(0);
  $c.gus.cfDisableObjects($p, [ed_acqClsStdt, ed_acqClsEnddt, ed_lsClntNo, btn_lsClnt, ed_lsTerm]);
  ed_lsClntNo.setValue("");
  ed_lsClntNm.setValue("");
  ed_acqClsStdt.setValue("");
  ed_acqClsEnddt.setValue("");
  ed_lsTerm.setValue("");
  ds_evidence.setCellData(0, "evidFileClsCd", "00");
  // default setting
  ed_vat.setValue(0); //증빙 부가세액
  ed_adjustExchRt.setValue(0); // 정산 통화코드/환율
  ed_payAmtFcrc.setValue(0); // 정산 외화
  ed_reqAmt.setValue(0); // 정산 정산금액

  //사업자번호 포맷 세팅
  ed_supplierCrn.setEditFormat('###-##||###-##-#####');
  ed_cardNo.setEditFormat('####-####||####-####-####||####-####-####-####');
  ed_zip.setEditFormat('###-###||###-##');

  //AsIs랑 화면을 맞추려는데 ref를 걸면 셀렉트 박스는 작동을 안함 (바꿔도 안바뀜)
  //ref를 풀면 index -1 을 줘야 empty 가 될텐데 change 이벤트 탐.
  // 그래서 끊고 값넣은 후 이벤트 별도 바인딩
  lc_outbrAcctCd.setSelectedIndex(-1);
  lc_outbrAcctCd.bind("onchange", scwin.lc_outbrAcctCd_onchange);
  lc_reqPayMthdCd.setSelectedIndex(-1);
};
