//-------------------------------------------------------------------------
// 자산종류 조회
//-------------------------------------------------------------------------
scwin.f_SrchAsetKnd = async function (asetKndCd) {
  var asetPatternCd = ds_excelUp.getCellData(ds_excelUp.getRowPosition(), 'asetPatternCd');
  let strAction = "/ac.fi.fixedaset.RetrieveFixedAsetKndListCMD.do?asetPatternCd=" + asetPatternCd + "&asetKndCd=" + asetKndCd;
  sbm_asetKnd.action = strAction;
  var res = await $c.sbm.execute($p, sbm_asetKnd);
  let rowCnt = ds_asetKnd.getRowCount();
  if (rowCnt == 0) {
    $c.gus.cfAlertMsg($p, "자산종류가 존재하지 않습니다.");
    ds_asetKnd.removeAll();
  } else if (rowCnt == 1) {
    //getRowCount 는 1이라도 index는 0 부터 
    ds_asetKnd.setRowPosition(0);
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "deprMthdCd", ds_asetKnd.getCellData(0, "deprMthdCd"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "deprMthdNm", ds_asetKnd.getCellData(0, "deprMthdNm"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "svcLife", ds_asetKnd.getCellData(0, "svcLife"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "deprRt", ds_asetKnd.getCellData(0, "deprRt"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawDeprMthdCd", ds_asetKnd.getCellData(0, "taxLawDeprMthdCd"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawDeprMthdNm", ds_asetKnd.getCellData(0, "taxLawDeprMthdNm"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawSvcLife", ds_asetKnd.getCellData(0, "taxLawSvcLife"));
    ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawDeprRt", ds_asetKnd.getCellData(0, "taxLawDeprRt"));
    //txt_fixedAsetNm.focus();
  } else {
    ds_asetKnd.removeAll();
    //if(cfCheckCreateFlag() == false) txt_asetKndNm.focus();
  }
};

