//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_SaveProc = async function () {
  let evidFileClsCd = ds_evidence.getCellData(0, "evidFileClsCd");
  if (fileUploadGDS.getRowCount() > 0) {
    if (evidFileClsCd == "" || evidFileClsCd == "00") {
      $c.win.alert($p, "증빙파일구분을 선택하세요");
      return;
    }
  }
  let changeExchRt;
  for (var i = 0; i < ds_adjustment.getRowCount(); i++) {
    if (lc_payCrcCd.getValue() != scwin.KOREA_WON) {
      changeExchRt = ds_adjustment.getCellData(i, "exchRt");
      dma_exchRtSearch.set("crcCd", ds_adjustment.getCellData(i, "payCrcCd"));
      dma_exchRtSearch.set("stdDt", ed_acqDt.getValue());
      //dma_exchRtSearch.UseChangeInfo = false;
      //tr_exchRt.Post();
      await $c.sbm.execute($p, sbm_exchRt);

      //alert( i + " => " + ds_exchRtSearch.text);
      scwin.checkExchRt = ds_exchRt.getCellData(ds_exchRt.getRowPosition(), "stdExchRt"); // 기준 환율			

      //alert(i + "번째 checkExchRt2 : " + checkExchRt);
      //alert(i + "번째 changeExchRt : " + changeExchRt);	    

      if (changeExchRt < checkExchRt * 0.9 || changeExchRt > checkExchRt * 1.1) {
        $c.win.alert($p, '통화코드 선택시 환율 금액 : ' + scwin.checkExchRt + '원' + '\n' + '환율의 90%  가 되는 금액  : ' + Math.round(scwin.checkExchRt * 0.9 * 100) / 100.00 + '원' + '\n' + '환율의 110% 가 되는 금액  : ' + Math.round(scwin.checkExchRt * 1.1 * 100) / 100.00 + '원' + '\n' + '\n' + i + "번째행에 입력된 환율은 기준 환율의 " + '\n' + "90% ~ 110% 사이의 값 이어야 합니다.");
        return;
      }
    }
  }
  let ret;
  if (ds_evidence.getModifiedIndex().length < 1) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, Array("자료"));
  } else {
    //입력 validation

    ret = await scwin.f_Validation();
    if (!ret) {
      return;
    }
    ret = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (ret) {
      // 가지급금 적요,정리일자
      for (i = 0; i < ds_prov.getRowCount(); i++) {
        for (j = 0; j < ds_provHeader.getRowCount(); j++) {
          if (ds_prov.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
            ds_prov.setCellData(i, "summary", ds_provHeader.getCellData(j, "summary"));
            ds_prov.setCellData(i, "setlDt", ds_provHeader.getCellData(j, "setlDt"));
            ds_prov.setCellData(i, "bankbookNo", ds_provHeader.getCellData(j, "bankbookNo"));
            break;
          }
        }
      }

      //tr_master.post();
      $c.sbm.execute($p, sbm_master);
      ds_evidence.removeAll(); //증빙 데이터셋
      ds_aset.removeAll(); //자산 데이터셋
      ds_adjustment.removeAll(); //정산 데이터셋
      ds_landinfo.removeAll(); //지번 데이터셋
      ds_provHeader.removeAll(); //선급금 헤더 데이터셋
      ds_prov.removeAll(); //선급금 내역 데이터셋
      ds_master.removeAll(); //지번 데이터셋	                 
      ds_excelUp.removeAll(); //엑셀 업로드 데이터셋			        
      //f_OnLoad();

      strPath = "/ui/ac/fi/fixedaset/fi_301_01_02b.xml";
      menuNm = "고정자산취득(업로드)";
      menuId = "fi_301_01_02b";
      paramObj = {};
      $c.win.openMenu($p, menuNm, strPath, menuId, paramObj, {
        openAction: "exist"
      });
    }
  }
};

