//-------------------------------------------------------------------------
// 정산 입력 Validation
//-------------------------------------------------------------------------
scwin.f_ValidateAdjustment = async function () {
  if (ds_adjustment.getRowCount() < 1) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, ["정산내역"]);
    return false;
  }
  let ret;
  ret = await $c.gus.cfValidate($p, [tbl_adjustment]);
  if (!ret) {
    return false;
  }
  if (lc_outbrAcctCd.getValue() == scwin.ADJM_MTHDCD_NOPAY) {
    if (lc_reqPayMthdCd.getItemCount() < 1) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["지급수단"]);
      lc_reqPayMthdCd.focus();
      return false;
    }

    //ret = $c.gus.cfValidateValue(ed_payDt.getValue(), "date=YYYYMMDD");
    ret = $c.date.isDate($p, ed_payDt.getValue());
    if (!ret) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["지급예정일"]);
      ed_payDt.focus();
      return false;
    }
  }

  //가지급선급금 정리금액 합계 체크
  let adjmAmt = 0,
    adjmAmtFcrc = 0,
    prepaySum = 0,
    prepaySumFcrc = 0;
  let adjmRow = ds_adjustment.getRowPosition();
  let adjmGubun = ds_adjustment.getCellData(adjmRow, "outbrAcctCd");

  //        if (adjmGubun == ADJM_MTHDCD_PREPAY || adjmGubun == ADJM_MTHDCD_SUSPAY) {
  if (adjmGubun == scwin.ADJM_MTHDCD_SUSPAY) {
    adjmAmt = Number(ds_adjustment.getCellData(adjmRow, "reqAmt"));
    adjmAmtFcrc = Number(ds_adjustment.getCellData(adjmRow, "payAmtFcrc"));
    for (j = 0; j < ds_prov.getRowCount(); j++) {
      if (ds_adjustment.getCellData(adjmRow, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
        prepaySum = prepaySum + Number(ds_prov.getCellData(j, "setlIntendAmt"));
        prepaySumFcrc = prepaySumFcrc + Number(ds_prov.getCellData(j, "setlIntendAmtFcrc"));
      }
    }
    if (prepaySum == 0 && lc_payCrcCd.getValue() == ACConstants.KOREA_WON) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("정리금액"));
      return false;
    }
    if (adjmAmt != prepaySum && lc_payCrcCd.getValue() == ACConstants.KOREA_WON) {
      let alertMsg = (adjmGubun == scwin.ADJM_MTHDCD_PREPAY ? "선급금" : "가지급금") + " 정산금액과 정리 금액의 합계가 다릅니다.";
      $c.gus.cfAlertMsg($p, alertMsg);
      ed_reqAmt.focus();
      return false;
    }
    if (prepaySumFcrc == 0 && lc_payCrcCd.getValue() != ACConstants.KOREA_WON) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("정리외화금액"));
      return false;
    }
    if (adjmAmtFcrc != prepaySumFcrc && lc_payCrcCd.getValue() != ACConstants.KOREA_WON) {
      var alertMsg = (adjmGubun == scwin.ADJM_MTHDCD_PREPAY ? "선급금" : "가지급금") + " 정산외화금액과 정리외화 금액의 합계가 다릅니다.";
      $c.gus.cfAlertMsg($p, alertMsg);
      ed_reqAmt.focus();
      return false;
    }
  }
  return true;
};

