scwin.f_ValidateAset = async function () {
  let ret;
  if (ds_aset.getRowCount() < 1) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, ["취득자산"]);
    return false;
  }
  ret = await $c.gus.cfValidate($p, [tbl_aset]);
  if (!ret) {
    return false;
  }
  ret = await scwin.f_ValidateAcqCls();
  if (ret == false) return false;
  return true;
};

//-------------------------------------------------------------------------
// 취득구분 Validation
// 취득구분이 금융리스(20), 할부금융(30) 일때 기간, 거래처 필수
//-------------------------------------------------------------------------
scwin.f_ValidateAcqCls = function () {
  let tempAcqCls = "";
  let cntAcctCd = 0;
  for (i = 0; i < ds_adjustment.getRowCount(); i++) {
    if (ds_adjustment.getCellData(i, "outbrAcctCd") == "11") cntAcctCd = cntAcctCd + 1;
  }
  if (lc_acqCls.getValue() == "20" || lc_acqCls.getValue() == "30") {
    // 금융리스(20), 할부금융(30)
    if ($c.gus.cfIsNull($p, ed_acqClsStdt.getValue()) || $c.gus.cfIsNull($p, ed_acqClsEnddt.getValue())) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["리스/할부기간(이)"]);
      return false;
    }
    if ($c.gus.cfIsNull($p, ed_lsClntNo.getValue())) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, ["리스/할부거래처"]);
      return false;
    }
  }
  if (lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY && lc_acqCls.getValue() != "30") {
    $c.gus.cfAlertMsg($p, "정산방법이 장기미지급금-일반인 경우 취득구분은 할부금융이여야 합니다.");
    lc_acqCls.focus();
    return false;
  } else if (lc_outbrAcctCd.getValue() != ACConstants.ADJM_MTHDCD_LONG_NOPAY && lc_acqCls.getValue() == "30") {
    $c.gus.cfAlertMsg($p, "취득구분이 할부금융인 경우 정산방법은 장기미지급금-일반이여야 합니다.");
    lc_acqCls.focus();
    return false;
  } else if (cntAcctCd < 1 && lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY_LEASE && lc_acqCls.getValue() != "20") {
    $c.gus.cfAlertMsg($p, "정산방법이 장기미지급금-리스부채인 경우 취득구분은 금융리스이여야 합니다.");
    lc_acqCls.focus();
    return false;
  } else if (cntAcctCd < 1 && lc_outbrAcctCd.getValue() != ACConstants.ADJM_MTHDCD_LONG_NOPAY_LEASE && lc_acqCls.getValue() == "20") {
    $c.gus.cfAlertMsg($p, "취득구분이 금융리스인 경우 정산방법은 장기미지급금-리스부채이여야 합니다.");
    lc_acqCls.focus();
    return false;
  } else if ((lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY_LEASE || lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY) && lc_acqCls.getValue() == "10") {
    $c.gus.cfAlertMsg($p, "정산방법이 장기미지급금-리스부채나 일반인 경우 취득구분은 현금을 선택 할 수 없습니다.");
    lc_acqCls.focus();
    return false;
  }

  //취득구분은 한가지로만 등록 가능 20160906 김지혜과장 요청
  for (i = 0; i < ds_aset.getRowCount(); i++) {
    if (i > 0 && tempAcqCls != ds_aset.getCellData(i, "acqCls")) {
      $c.gus.cfAlertMsg($p, "취득구분은 모두 같아야합니다..");
      lc_acqCls.focus();
      return false;
    }
    tempAcqCls = ds_aset.getCellData(i, "acqCls");
  }
  return true;
};

//-------------------------------------------------------------------------
// 면적관리 입력 Validation
//-------------------------------------------------------------------------
scwin.f_ValidateAreaMgnt = function () {
  //면적관리를 하지 않으면 리턴

  //if (chb_areaMgntYn.getValue() == "")
  if (ds_asetPattern.getCellData(ds_asetPattern.getRowPosition(), 'areaMgntYn') == "") return true;
  if ($c.gus.cfIsNull($p, ed_zip.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_003, ["우편번호"]);
    ed_zip.focus();
    return false;
  }
  if ($c.gus.cfIsNull($p, ed_siteAddr1.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_003, ["주소"]);
    ed_zip.focus();
    return false;
  }
  if ($c.gus.cfIsNull($p, ed_siteAddr2.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_003, ["상세주소"]);
    ed_siteAddr2.focus();
    return false;
  }
  if ($c.gus.cfIsNull($p, ed_area.getValue()) || parseInt(ed_area.getValue()) <= 0) {
    $c.gus.cfAlertMsg($p, "면적은 0보다 큰 값이어야 합니다.");
    ed_area.focus();
    return false;
  }
  if ($c.gus.cfIsNull($p, ed_pyCnt.getValue()) || parseInt(ed_pyCnt.getValue()) <= 0) {
    $c.gus.cfAlertMsg($p, "평수는 0보다 큰 값이어야 합니다.");
    ed_pyCnt.focus();
    return false;
  }
  if (ds_master.getRowCount() < 1) {
    $c.gus.cfAlertMsg($p, "지번_지목 내역을 한 행이상 입력해야 합니다.");
    return false;
  }
  scwin.f_SaveData();
  return true;
};

