scwin.f_SaveData = function () {
  //ds_master.ViewDeletedRow = false; //삭제된 행 숨기기 기능 ??

  let changeExchRt = ds_adjustment.getCellData(ds_adjustment.getRowPosition(), "exchRt");
  if (!$c.gus.cfCheckExchRt($p, scwin.checkExchRt, changeExchRt, scwin.checkMain))
    // 저장버튼 클릭시 환율에 대한 체크를 하는 함수 호출
    return;
  scwin.f_UndoAllValueRow(ds_landinfo, "tempAsetNo", ds_aset.getCellData(ds_aset.getRowPosition(), "tempAsetNo"));
  return scwin.f_CopyDataSet(ds_master, ds_landinfo);
  //ds_landinfo.RowPosition = (ds_landinfo.CountRow - ds_master.CountRow + 1);
};

//-------------------------------------------------------------------------
//  Dataset의 Row 중 주어진 컬럼의 값을 가진 Row 취소 처리
//-------------------------------------------------------------------------
function f_UndoAllValueRow(dataSet, sColumn, columnValue) {
  if (dataSet == null) return;
  if (sColumn == "") return;
  if (columnValue == "") return;
  while (scwin.f_FindValueRow(dataSet, sColumn, columnValue) != 0) {
    //dataSet.Undo(f_FindValueRow(dataSet, sColumn, columnValue));
    $c.data.undoRow($p, dataSet, "Y");
  }
}

