//-------------------------------------------------------------------------
// 입력한 달수를 통해 계약종료일 계산
//-------------------------------------------------------------------------
scwin.f_CalEndDt = function (mm) {
  if (mm == "" || mm == "0" || ed_acqClsStdt.getValue() == "") {
    ed_acqClsEnddt.setValue("");
    ed_lsTerm.setValue("");
    return;
  }
  let startDtm = ed_acqClsStdt.getValue();
  let endDtm = ed_acqClsEnddt.getValue();
  if (startDtm.length == 8 && parseInt(mm, 10) > 0) {
    let startDate = new Date(parseInt(startDtm.substring(0, 4), 10), parseInt(startDtm.substring(4, 6), 10) - 1, parseInt(startDtm.substring(6, 8), 10));
    startDate.setHours(0);
    startDate.setMinutes(0);
    startDate.setSeconds(0);
    let endDate = startDate;
    let curMonth = endDate.getMonth() + 1;
    let plusMonth = curMonth + parseInt(mm, 10);
    if (plusMonth > 12) {
      let share = Math.floor(plusMonth / 12);
      endDate.setFullYear(endDate.getFullYear() + share);
      let rest = plusMonth % 12;
      if (rest > 0) {
        endDate.setMonth(rest - 1);
      } else {
        endDate.setMonth(0);
      }
    } else {
      endDate.setMonth(plusMonth - 1);
    }
    ed_acqClsEnddt.setValue(endDate);
  }
};

/*
<script language=JavaScript for=ed_lsTerm event=OnKillFocus()>
*/
scwin.ed_lsTerm_onblur = function (e) {
  scwin.f_CalEndDt(this.getValue());
};

